/**
 * MedX footer layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Footer compliance links and version strip.
 */
const FOOTER_TOKENS = Object.freeze({
  primary: { value: "layout-footer-primary", scope: "layout" },
  secondary: { value: "layout-footer-secondary", scope: "layout" },
  muted: { value: "layout-footer-muted", scope: "layout" },
  accent: { value: "layout-footer-accent", scope: "layout" },
  surface: { value: "layout-footer-surface", scope: "layout" },
});

const FOOTER_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const FOOTER_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const footerRegistry = new Map();
const FOOTER_listeners = new Set();
let FOOTER_seq = 0;

function createFooterId(prefix = "medx-layout-footer") {
  FOOTER_seq += 1;
  return `${prefix}-${FOOTER_seq}`;
}

function registerFooter(config = {}) {
  const entryId = config.id ?? createFooterId();
  const preset = FOOTER_PRESETS[config.preset ?? "default"] ?? FOOTER_PRESETS.default;
  const token = FOOTER_TOKENS[config.token ?? preset.token] ?? FOOTER_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: FOOTER_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  footerRegistry.set(entryId, entry);
  notifyFooterListeners("register", entry);
  return entry;
}

function updateFooter(id, patch = {}) {
  const entry = footerRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyFooterListeners("update", entry);
  return entry;
}

function resolveFooter(id) {
  const entry = footerRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listFooterEntries(filter = {}) {
  let items = Array.from(footerRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onFooterEvent(listener) {
  FOOTER_listeners.add(listener);
  return () => FOOTER_listeners.delete(listener);
}

function notifyFooterListeners(type, entry) {
  for (const listener of FOOTER_listeners) {
    try {
      listener({ type, entry, registrySize: footerRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:footer] listener error", err.message);
    }
  }
}

function getFooterMetrics() {
  const items = listFooterEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(FOOTER_TOKENS).length,
    presets: Object.keys(FOOTER_PRESETS).length,
  };
}

async function runMedxFooter() {
  console.log("[medx:ui:layout:footer] runtime initialized");
  console.log(`[medx:ui:layout:footer] tokens=${Object.keys(FOOTER_TOKENS).length} presets=${Object.keys(FOOTER_PRESETS).length}`);

  const events = [];
  onFooterEvent((e) => events.push(e.type));

  const domains = Object.keys(FOOTER_SUPPLY_CHAIN);
  const presets = Object.keys(FOOTER_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerFooter({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/footer" },
    });
  }

  const first = listFooterEntries()[0];
  if (first) updateFooter(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getFooterMetrics();
  const resolved = first ? resolveFooter(first.id) : null;

  console.log(`[medx:ui:layout:footer] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:footer] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:footer] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:footer] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:footer] bootstrap complete");
}

module.exports = runMedxFooter;
